import React, { useState, useEffect, useRef } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  Animated,
  Dimensions,
  Platform,
} from 'react-native';
import {
  SafeAreaContainer,
  BottomTabs,
  OfflineDot,
  SafeArrivalBanner,
  Colors,
} from '../components/Layout';
import { useIncidentStore } from '../store';
import { TOTAL_CONTACTS_DEMO } from '../services/mockData';
import { EMERGENCY_DB } from '../services/emergencyDB';

const SIDE_PAD = 16;
const GAP = 10;
const { width: SCREEN_W } = Dimensions.get('window');
const CELL_W = (SCREEN_W - SIDE_PAD * 2 - GAP) / 2;

// ─── INCIDENT BUTTON ─────────────────────────────────────────────────────────
interface IncidentBtnProps {
  label: string;
  sublabel: string;
  severity: 'critical' | 'high' | 'medium' | 'guarded';
  onPress: () => void;
  height?: number;
}

const SEVERITY_COLORS = {
  critical: { bg: '#7B1111', border: '#9B2020', badge: '#C0392B', text: 'CRITICAL' },
  high:     { bg: '#7A3B00', border: '#994B00', badge: '#E67E22', text: 'HIGH' },
  medium:   { bg: '#0D2E5C', border: '#1A3F78', badge: '#2980B9', text: 'ACTIVE' },
  guarded:  { bg: '#1A1A2E', border: '#2D2D4A', badge: '#7D3C98', text: 'PRIORITY' },
};

const IncidentBtn: React.FC<IncidentBtnProps> = ({ label, sublabel, severity, onPress, height = 90 }) => {
  const scale = useRef(new Animated.Value(1)).current;
  const glow  = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (severity === 'critical') {
      Animated.loop(
        Animated.sequence([
          Animated.timing(glow, { toValue: 1, duration: 1800, useNativeDriver: true }),
          Animated.timing(glow, { toValue: 0, duration: 1800, useNativeDriver: true }),
        ])
      ).start();
    }
  }, []);

  const onIn  = () => Animated.spring(scale, { toValue: 0.96, useNativeDriver: true, speed: 60 }).start();
  const onOut = () => Animated.spring(scale, { toValue: 1, useNativeDriver: true, speed: 60 }).start();

  const c = SEVERITY_COLORS[severity];
  const borderOpacity = glow.interpolate({ inputRange: [0, 1], outputRange: [0.6, 1] });

  return (
    <Animated.View style={{ transform: [{ scale }], flex: 1 }}>
      <TouchableOpacity
        style={[ss.incBtn, { backgroundColor: c.bg, borderColor: c.border, height }]}
        onPress={onPress} onPressIn={onIn} onPressOut={onOut} activeOpacity={1}
      >
        {/* Severity badge */}
        <View style={[ss.severityBadge, { backgroundColor: c.badge }]}>
          <Text style={ss.severityText}>{c.text}</Text>
        </View>
        <Text style={ss.incBtnLabel}>{label}</Text>
        <Text style={ss.incBtnSub}>{sublabel}</Text>
        <Animated.View style={[ss.incBtnArrow, { opacity: borderOpacity }]}>
          <Text style={{ color: 'rgba(255,255,255,0.5)', fontSize: 16, fontWeight: '300' }}>›</Text>
        </Animated.View>
      </TouchableOpacity>
    </Animated.View>
  );
};

// ─── QUICK ACCESS ITEM ────────────────────────────────────────────────────────
const QuickItem: React.FC<{ label: string; sub: string; onPress: () => void }> = ({ label, sub, onPress }) => (
  <TouchableOpacity style={ss.quickItem} onPress={onPress}>
    <View style={{ flex: 1 }}>
      <Text style={ss.quickItemLabel}>{label}</Text>
      <Text style={ss.quickItemSub}>{sub}</Text>
    </View>
    <Text style={{ color: Colors.gray500, fontSize: 16, fontWeight: '300' }}>›</Text>
  </TouchableOpacity>
);

// ─── HOME SCREEN ─────────────────────────────────────────────────────────────
export const HomeScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const [activeTab, setActiveTab] = useState('home');
  const { offlineStatus, safeArrival, clearSafeArrival } = useIncidentStore();
  const counterAnim = useRef(new Animated.Value(0)).current;
  const [displayCount, setDisplayCount] = useState(0);

  useEffect(() => {
    const listener = counterAnim.addListener(({ value }) => setDisplayCount(Math.floor(value)));
    Animated.timing(counterAnim, { toValue: TOTAL_CONTACTS_DEMO, duration: 2200, useNativeDriver: false }).start();
    return () => counterAnim.removeListener(listener);
  }, []);

  const nav = (screen: string, params?: any) =>
    navigation.navigate('EmergencyFlows', { screen, params });
  const navSupport = (screen: string) =>
    navigation.navigate('SupportFlows', { screen });

  const tabs = [
    { id: 'home',    icon: '⬜', label: 'Home',       action: () => setActiveTab('home') },
    { id: 'profile', icon: '◯',  label: 'Profile',    action: () => setActiveTab('profile') },
    { id: 'qr',      icon: '▦',  label: 'Medical ID', action: () => navSupport('MedicalID') },
    { id: 'arrival', icon: '◷',  label: 'Safe Drive', action: () => navSupport('SafeArrival') },
  ];

  return (
    <SafeAreaContainer style={{ flex: 1, backgroundColor: '#F2F4F6' }}>
      {/* ── Header ── */}
      <View style={ss.header}>
        <View style={ss.headerLeft}>
          <View style={ss.brandMark}>
            <Text style={ss.brandMarkText}>R</Text>
          </View>
          <View>
            <Text style={ss.brandName}>ROADSoS</Text>
            <Text style={ss.brandTagline}>Emergency Response System</Text>
          </View>
        </View>
        <View style={ss.headerRight}>
          <OfflineDot status={offlineStatus === 'none' ? 'live' : offlineStatus} />
          <TouchableOpacity onPress={() => setActiveTab('profile')} style={ss.profilePill}>
            <Text style={ss.profilePillText}>Profile</Text>
          </TouchableOpacity>
        </View>
      </View>

      {/* ── Safe Arrival Banner ── */}
      {safeArrival.deadline && (
        <SafeArrivalBanner
          destination={safeArrival.destination}
          deadline={safeArrival.deadline}
          onCheckIn={clearSafeArrival}
        />
      )}

      <ScrollView contentContainerStyle={ss.scroll} showsVerticalScrollIndicator={false}>
        {activeTab === 'home' && <HomeContent nav={nav} navSupport={navSupport} displayCount={displayCount} />}
        {activeTab === 'profile' && <ProfileContent navigation={navigation} />}
      </ScrollView>

      <BottomTabs activeTab={activeTab} tabs={tabs} />
    </SafeAreaContainer>
  );
};

// ─── HOME CONTENT ─────────────────────────────────────────────────────────────
const HomeContent: React.FC<{
  nav: (s: string, p?: any) => void;
  navSupport: (s: string) => void;
  displayCount: number;
}> = ({ nav, navSupport, displayCount }) => (
  <>
    {/* Section label */}
    <View style={ss.sectionHeader}>
      <Text style={ss.sectionHeaderLabel}>EMERGENCY TYPE</Text>
      <Text style={ss.sectionHeaderSub}>Select the nature of your incident</Text>
    </View>

    {/* ── Row 1: Accident — full width ── */}
    <IncidentBtn
      label="Accident / Road Crash"
      sublabel="Triage assessment · Ambulance · Police · First aid"
      severity="critical"
      onPress={() => nav('Triage')}
      height={100}
    />

    {/* ── Row 2: Car Fire — full width ── */}
    <View style={{ marginTop: GAP }}>
      <IncidentBtn
        label="Vehicle Fire"
        sublabel="Evacuation protocol · Fire brigade · Gas station alert"
        severity="high"
        onPress={() => nav('EvacuationGuide')}
        height={88}
      />
    </View>

    {/* ── 2×2 Grid ── */}
    <View style={{ flexDirection: 'row', marginTop: GAP, gap: GAP }}>
      {/* Col 1 */}
      <View style={{ width: CELL_W, gap: GAP }}>
        <IncidentBtn
          label="Breakdown"
          sublabel="Towing · Tyres · Showrooms"
          severity="medium"
          onPress={() => nav('EmergencyBreakdown', { defaultTab: 0 })}
        />
        <IncidentBtn
          label="Flood / Disaster"
          sublabel="NDRF · Shelters · Safe routes"
          severity="medium"
          onPress={() => nav('EmergencyFlood')}
        />
      </View>
      {/* Col 2 */}
      <View style={{ width: CELL_W, gap: GAP }}>
        <IncidentBtn
          label="Out of Fuel"
          sublabel="Nearest petrol pumps"
          severity="medium"
          onPress={() => nav('EmergencyBreakdown', { defaultTab: 2 })}
        />
        <IncidentBtn
          label="Crime / Theft"
          sublabel="Silent SOS · GPS tracking"
          severity="guarded"
          onPress={() => nav('EmergencySOS')}
        />
      </View>
    </View>

    {/* ── Stats row ── */}
    <View style={ss.statsRow}>
      <View style={ss.statCell}>
        <Text style={ss.statValue}>{displayCount}+</Text>
        <Text style={ss.statLabel}>Emergency\nContacts</Text>
      </View>
      <View style={ss.statDivider} />
      <View style={ss.statCell}>
        <Text style={ss.statValue}>{EMERGENCY_DB.length - 1}</Text>
        <Text style={ss.statLabel}>Countries\nCovered</Text>
      </View>
      <View style={ss.statDivider} />
      <View style={ss.statCell}>
        <Text style={ss.statValue}>100%</Text>
        <Text style={ss.statLabel}>Offline\nCapable</Text>
      </View>
    </View>

    {/* ── Tools Section ── */}
    <View style={ss.sectionHeader}>
      <Text style={ss.sectionHeaderLabel}>TOOLS & RESOURCES</Text>
    </View>

    <View style={ss.toolsCard}>
      <QuickItem
        label="Bystander Assistance"
        sub="I'm at the scene — assign me a rescue role"
        onPress={() => navSupport('BystanderEntry')}
      />
      <View style={ss.toolDivider} />
      <QuickItem
        label="CPR Metronome Guide"
        sub="100–120 BPM pacing · Step-by-step protocol"
        onPress={() => navSupport('CPRGuide')}
      />
      <View style={ss.toolDivider} />
      <QuickItem
        label="Medical QR Identity Card"
        sub="Offline QR code for first responders"
        onPress={() => navSupport('MedicalID')}
      />
      <View style={ss.toolDivider} />
      <QuickItem
        label="Accident Report / FIR"
        sub="Auto-generate a shareable incident report"
        onPress={() => navSupport('AccidentReport')}
      />
      <View style={ss.toolDivider} />
      <QuickItem
        label="Incident Map"
        sub="View and report active incidents nearby"
        onPress={() => nav('IncidentMap')}
      />
      <View style={ss.toolDivider} />
      <QuickItem
        label="Safe Arrival Monitor"
        sub="Set a trip deadline with auto-alert to contacts"
        onPress={() => navSupport('SafeArrival')}
      />
    </View>

    {/* ── Coverage ── */}
    <View style={ss.coverageCard}>
      <Text style={ss.coverageTitle}>GLOBAL COVERAGE</Text>
      <Text style={ss.coverageSub}>Auto-detects your country from GPS and displays local emergency numbers</Text>
      <ScrollView horizontal showsHorizontalScrollIndicator={false} style={{ marginTop: 12 }}>
        <View style={{ flexDirection: 'row', gap: 6, paddingRight: 8 }}>
          {EMERGENCY_DB.filter(c => c.code !== 'EU').slice(0, 12).map((c) => (
            <View key={c.code} style={ss.countryChip}>
              <Text style={{ fontSize: 16 }}>{c.flag}</Text>
              <Text style={ss.countryChipCode}>{c.code}</Text>
            </View>
          ))}
          <View style={[ss.countryChip, { backgroundColor: Colors.accent + '22', borderColor: Colors.accent + '55', justifyContent: 'center' }]}>
            <Text style={{ fontSize: 12, color: Colors.accent, fontWeight: '800' }}>+{EMERGENCY_DB.length - 13}</Text>
          </View>
        </View>
      </ScrollView>
    </View>
  </>
);

// ─── PROFILE CONTENT ─────────────────────────────────────────────────────────
const ProfileContent: React.FC<{ navigation: any }> = ({ navigation }) => {
  const {
    userName, userPhone, emergencyContacts, medicalDetails,
    language, offlineStatus, setOfflineStatus, locationOverride, setLocationOverride,
  } = useIncidentStore();

  return (
    <ScrollView showsVerticalScrollIndicator={false}>
      {/* User card */}
      <View style={ss.userCard}>
        <View style={ss.userAvatarRing}>
          <View style={ss.userAvatar}>
            <Text style={{ fontSize: 28, color: Colors.gray300 }}>
              {userName ? userName[0].toUpperCase() : '—'}
            </Text>
          </View>
        </View>
        <View style={{ flex: 1 }}>
          <Text style={ss.userName}>{userName || 'Profile not configured'}</Text>
          <Text style={ss.userPhone}>{userPhone || 'No phone number set'}</Text>
        </View>
        <TouchableOpacity style={ss.editBtn} onPress={() => navigation.navigate('Setup')}>
          <Text style={ss.editBtnText}>Edit</Text>
        </TouchableOpacity>
      </View>

      {/* Emergency contacts */}
      <PCard title="EMERGENCY CONTACTS">
        {emergencyContacts.length === 0 ? (
          <TouchableOpacity onPress={() => navigation.navigate('Setup')}>
            <Text style={ss.emptyLink}>+ Configure emergency contacts</Text>
          </TouchableOpacity>
        ) : (
          emergencyContacts.map((c, i) => (
            <PRow key={i} label={`Contact ${i + 1}`} value={`${c.name}  ·  ${c.phone}`} />
          ))
        )}
      </PCard>

      {/* Medical */}
      <PCard title="MEDICAL INFORMATION">
        <PRow label="Blood Group" value={medicalDetails.bloodGroup || 'Not set'} highlight={!!medicalDetails.bloodGroup} />
        <PRow label="Allergies"   value={medicalDetails.allergies   || 'None recorded'} />
        <PRow label="Medications" value={medicalDetails.medications || 'None recorded'} />
      </PCard>

      {/* Language */}
      <PCard title="LANGUAGE">
        <PRow label="Display Language" value={{ en: 'English', hi: 'Hindi (हिंदी)', gu: 'Gujarati (ગુજ)' }[language] ?? 'English'} />
      </PCard>

      {/* Demo controller */}
      <PCard title="DEMO PRESENTATION CONTROLS">
        <Text style={ss.controlLabel}>Network Mode</Text>
        <View style={ss.controlRow}>
          <TouchableOpacity
            style={[ss.controlBtn, offlineStatus !== 'offline' && ss.controlBtnActive]}
            onPress={() => setOfflineStatus('live')}
          >
            <View style={[ss.controlDot, { backgroundColor: Colors.successLight }]} />
            <Text style={[ss.controlBtnText, offlineStatus !== 'offline' && { color: Colors.gray100 }]}>Live Network</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[ss.controlBtn, offlineStatus === 'offline' && ss.controlBtnActive]}
            onPress={() => setOfflineStatus('offline')}
          >
            <View style={[ss.controlDot, { backgroundColor: Colors.warning }]} />
            <Text style={[ss.controlBtnText, offlineStatus === 'offline' && { color: Colors.gray100 }]}>Offline Mode</Text>
          </TouchableOpacity>
        </View>

        <Text style={[ss.controlLabel, { marginTop: 16 }]}>GPS Country Override</Text>
        <View style={ss.chipGrid}>
          {[
            { label: 'Auto GPS',    code: null, lat: 0,       lng: 0,        loc: '' },
            { label: 'India (IN)',  code: 'IN', lat: 28.632,  lng: 77.219,   loc: 'New Delhi, India' },
            { label: 'USA (US)',    code: 'US', lat: 40.7128, lng: -74.006,  loc: 'New York, USA' },
            { label: 'UK (GB)',     code: 'GB', lat: 51.5074, lng: -0.1278,  loc: 'London, UK' },
            { label: 'Japan (JP)',  code: 'JP', lat: 35.6762, lng: 139.6503, loc: 'Tokyo, Japan' },
          ].map((item) => {
            const isActive = item.code === null ? locationOverride === null : locationOverride?.countryCode === item.code;
            return (
              <TouchableOpacity
                key={item.label}
                style={[ss.chip, isActive && ss.chipActive]}
                onPress={() => {
                  if (item.code === null) setLocationOverride(null);
                  else setLocationOverride({ lat: item.lat, lng: item.lng, label: item.loc, countryCode: item.code! });
                }}
              >
                <Text style={[ss.chipText, isActive && ss.chipTextActive]}>{item.label}</Text>
              </TouchableOpacity>
            );
          })}
        </View>

        <View style={ss.statusBadge}>
          <Text style={ss.statusBadgeText}>
            {locationOverride ? `Overriding GPS: ${locationOverride.label}` : 'Using real GPS coordinates'}
          </Text>
        </View>
      </PCard>

      {/* Quick links */}
      <View style={ss.toolsCard}>
        <QuickItem label="Medical QR Identity Card" sub="Offline-accessible QR for responders"          onPress={() => navigation.navigate('SupportFlows',   { screen: 'MedicalID' })} />
        <View style={ss.toolDivider} />
        <QuickItem label="Safe Arrival Monitor"     sub="Trip deadline with emergency auto-alert"        onPress={() => navigation.navigate('SupportFlows',   { screen: 'SafeArrival' })} />
        <View style={ss.toolDivider} />
        <QuickItem label="CPR Metronome Guide"      sub="Interactive life-saving cardiac protocol"       onPress={() => navigation.navigate('SupportFlows',   { screen: 'CPRGuide' })} />
        <View style={ss.toolDivider} />
        <QuickItem label="Accident Report / FIR"    sub="Generate and share an incident report"          onPress={() => navigation.navigate('SupportFlows',   { screen: 'AccidentReport' })} />
        <View style={ss.toolDivider} />
        <QuickItem label="Bystander Assistance"     sub="Assign rescue roles at a crash scene"           onPress={() => navigation.navigate('SupportFlows',   { screen: 'BystanderEntry' })} />
        <View style={ss.toolDivider} />
        <QuickItem label="Incident Map"             sub="View and report live incidents nearby"          onPress={() => navigation.navigate('EmergencyFlows', { screen: 'IncidentMap' })} />
      </View>

      {/* Reset */}
      <View style={{ marginTop: 8, marginBottom: 32 }}>
        <TouchableOpacity
          style={ss.resetBtn}
          onPress={async () => {
            const AsyncStorage = require('@react-native-async-storage/async-storage').default;
            await AsyncStorage.clear();
            alert('Data cleared. Reload to restart onboarding.');
            if ((window as any)?.location) (window as any).location.reload();
          }}
        >
          <Text style={ss.resetBtnText}>Reset App Data  ·  Restart Onboarding</Text>
        </TouchableOpacity>
      </View>
    </ScrollView>
  );
};

